const assert = require('assert');
const { _siftdown } = require('./translated.js');

// Helper function to run assertions
function assertArrayEqual(actual, expected) {
    assert.deepStrictEqual(actual, expected);
}

// Test basic sift down operations
function testBasicSiftdown() {
    let heap = [1, 3, 5];
    _siftdown(heap, 0, 2);
    assertArrayEqual(heap, [1, 3, 5]); // No changes needed, heap property maintained

    heap = [5, 3, 1];
    _siftdown(heap, 0, 2);
    assertArrayEqual(heap, [1, 3, 5]); // Element 1 moved up to root position

    console.log("Basic siftdown tests passed");
}

// Test sift down with multiple levels in the heap
function testSiftdownWithMultipleLevels() {
    const heap = [0, 10, 20, 30, 40, 50, 60, 70, 5];
    _siftdown(heap, 0, 8);
    assertArrayEqual(heap, [0, 5, 20, 10, 40, 50, 60, 70, 30]); // 5 moves up

    console.log("Multiple level siftdown tests passed");
}

// Test edge cases
function testSiftdownEdgeCases() {
    // Single element heap
    let heap = [10];
    _siftdown(heap, 0, 0);
    assertArrayEqual(heap, [10]); // No change

    // Two element heap, no change needed
    heap = [5, 10];
    _siftdown(heap, 0, 1);
    assertArrayEqual(heap, [5, 10]); // No change needed

    // Two element heap, change needed
    heap = [10, 5];
    _siftdown(heap, 0, 1);
    assertArrayEqual(heap, [5, 10]); // 5 moves up to root position

    console.log("Edge case siftdown tests passed");
}

// Test more complex sift down scenarios
