        testSiftdownWithMultipleLevels();
        testSiftdownEdgeCases();
        testSiftdownComplex();
        testSiftdownNegativeNumbers();
        console.log("All tests passed successfully");
    } catch (error) {
        console.error("Test failed:", error.message);
        throw error;
    }
