if (n === 1) {
  var it = iterable[Symbol.iterator]();
  var first = it.next();
  if (first.done) {
    return []; // Empty iterable
  }
  var smallest = first.value;
  while (true) {
    var next = it.next();
    if (next.done) break;
    if (next.value < smallest) smallest = next.value;
  }
  return [smallest];
}

This would properly handle empty iterables and avoid the spread operator which could cause issues with large iterables.

