  const result = heappop(heap);
  console.assert(result === 3, "Expected result to be 3");
  console.assert(heap.length === 0, "Expected heap to be empty");
  console.log("Test heappop single element heap: PASSED");
}

function testHeappopMultipleElements() {
  const heap = [1, 5, 3, 8, 7];
  // Pop the smallest element (root)
  const result = heappop(heap);
  console.assert(result === 1, "Expected result to be 1");
  // The next smallest should now be at the root
  console.assert(heap[0] === 3, "Expected heap[0] to be 3");
  console.assert(heap.length === 4, "Expected heap.length to be 4");
  console.log("Test heappop multiple elements: PASSED");
}

function testHeappopOrdering() {
  const heap = [1, 5, 3, 8, 7];
  heappop(heap);
  // Check that heap property is maintained after popping
  let heapPropertyMaintained = true;
  for (let i = 0; i < heap.length; i++) {
    const leftChild = 2 * i + 1;
    const rightChild = 2 * i + 2;
    if (leftChild < heap.length) {
      if (heap[leftChild] < heap[i]) {
        heapPropertyMaintained = false;
        break;
      }
    }
    if (rightChild < heap.length) {
      if (heap[rightChild] < heap[i]) {
        heapPropertyMaintained = false;
        break;
      }
    }
  }
  console.assert(heapPropertyMaintained, "Heap property should be maintained");
  console.log("Test heappop ordering: PASSED");
}

function testHeappopConsecutiveCalls() {
  const heap = [2, 4, 6, 8, 10];
  const results = [];
  for (let i = 0; i < 5; i++) {
    results.push(heappop(heap));
  }
  console.assert(JSON.stringify(results) === JSON.stringify([2, 4, 6, 8, 10]), 
